\ Address of a glyph's bitmap in the table (its byte offset is ch*font-h).
: >glyph ( ch -- addr )  255 and  font-h *  (glyphs) + ;

\ Draw one glyph in `color` with its top-left at pixel x,y.  0-bits are
\ transparent (it is a `stamp`), so glyphs compose over anything drawn.
\ Not named `char`: that is the standard word ( "name" -- c ).
: glyph ( color ch x y -- )
    >r >r                                   \ R: x y  ( x on top )
    >glyph                                  ( color src )
    r> r>                                   ( color src x y )
    font-w font-h stamp ;

variable (t-col)  variable (t-adr)          \ text pen state: color, string,
variable (t-x)    variable (t-y)  variable (t-x0)   \ pen x/y, and line start x

\ Draw a string with its top-left at x,y, one glyph every font-w pixels.
\ A newline (10) returns to the start column and drops down font-h; a
\ carriage return (13) is ignored.  Off-screen glyphs clip, via `stamp`.
: text ( color c-addr u x y -- )
    (t-y) !  dup (t-x0) !  (t-x) !          ( color c-addr u )
    >r  (t-adr) !  (t-col) !                \ empty; R: u
    r> 0 ?do
        (t-adr) @ i + c@                    ( ch )
        dup 10 = if   drop
            (t-x0) @ (t-x) !  font-h (t-y) +!
        else dup 13 = if  drop
        else
            (t-col) @ swap (t-x) @ (t-y) @ glyph
            font-w (t-x) +!
        then then
    loop ;
